WITH p AS (SELECT $1::jsonb AS body)
SELECT castor_product_mix(
  (p.body->>'user_id')::uuid,
  (p.body->>'cliente_codigo'),
  COALESCE(NULLIF(p.body->>'limit','')::int, 15)
) AS result FROM p;

